import{_ as h,o as i,c as t,a0 as a}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"Email","description":"","frontmatter":{"title":"Email"},"headers":[],"relativePath":"email.md","filePath":"email.md"}'),l={name:"email.md"};function o(c,n,e,g,r,m){return i(),t("div",null,[...n[0]||(n[0]=[a('<h1 id="email" tabindex="-1">Email <a class="header-anchor" href="#email" aria-label="Permalink to &quot;Email&quot;">​</a></h1><p>Mô-đun <strong>Email</strong> trong ABNERP cung cấp hệ thống giao tiếp qua email tích hợp toàn diện, cho phép doanh nghiệp quản lý tài khoản email, tạo mẫu, gửi bản tin và tự động hóa thông báo trực tiếp từ nền tảng.</p><h2 id="tai-khoan-email" tabindex="-1">Tài khoản email <a class="header-anchor" href="#tai-khoan-email" aria-label="Permalink to &quot;Tài khoản email&quot;">​</a></h2><p><strong>Tài khoản email (Email Account)</strong> là cầu nối giữa ABNERP và máy chủ email của bạn. Hệ thống hỗ trợ kết nối với bất kỳ máy chủ SMTP/IMAP nào (Gmail, Outlook, máy chủ riêng, v.v.) và cho phép:</p><ul><li>Gửi và nhận email trực tiếp trong hệ thống</li><li>Tự động liên kết email với hồ sơ khách hàng, nhà cung cấp hoặc đơn hàng</li><li>Hỗ trợ nhiều tài khoản email cho các phòng ban khác nhau</li></ul><h2 id="mau-email" tabindex="-1">Mẫu email <a class="header-anchor" href="#mau-email" aria-label="Permalink to &quot;Mẫu email&quot;">​</a></h2><p><strong>Mẫu email (Email Template)</strong> cho phép tạo các mẫu nội dung chuyên nghiệp, đồng nhất. Mẫu có thể bao gồm các trường động như tên khách hàng, số đơn hàng, ngày tháng — giúp cá nhân hóa từng email tự động. Người dùng có thể thiết kế mẫu với HTML hoặc sử dụng trình soạn thảo trực quan, lưu trữ và tái sử dụng cho nhiều mục đích khác nhau.</p><h2 id="ban-tin" tabindex="-1">Bản tin <a class="header-anchor" href="#ban-tin" aria-label="Permalink to &quot;Bản tin&quot;">​</a></h2><p><strong>Bản tin (Newsletter)</strong> là công cụ gửi email hàng loạt đến danh sách người nhận. Người dùng có thể:</p><ul><li>Tạo bản tin từ mẫu email có sẵn</li><li>Chọn nhóm người nhận (khách hàng, nhà cung cấp, thành viên)</li><li>Gửi ngay hoặc lên lịch gửi sau</li><li>Chạy thử (test) trước khi gửi chính thức</li><li>Theo dõi tỷ lệ mở, tỷ lệ nhấp và phản hồi</li></ul><blockquote><p><strong>Lưu ý</strong>: Bản tin chỉ gửi đến các địa chỉ email đã được xác nhận đồng ý nhận tin, đảm bảo tuân thủ quy định chống thư rác.</p></blockquote><h2 id="thong-bao" tabindex="-1">Thông báo <a class="header-anchor" href="#thong-bao" aria-label="Permalink to &quot;Thông báo&quot;">​</a></h2><p><strong>Thông báo (Notification)</strong> là hệ thống cảnh báo tự động gửi email khi có sự kiện quan trọng xảy ra trong hệ thống. Người dùng có thể thiết lập thông báo cho các tình huống như:</p><ul><li>Đơn hàng mới được tạo</li><li>Hết hàng tồn kho</li><li>Hóa đơn quá hạn thanh toán</li><li>Duyệt đơn mua hàng hoặc yêu cầu mua hàng</li><li>Phiếu bảo trì sắp đến hạn</li></ul><h2 id="bao-cao-email-tu-đong" tabindex="-1">Báo cáo email tự động <a class="header-anchor" href="#bao-cao-email-tu-đong" aria-label="Permalink to &quot;Báo cáo email tự động&quot;">​</a></h2><p><strong>Báo cáo email tự động (Auto Email Report)</strong> cho phép lên lịch gửi báo cáo định kỳ qua email. Người dùng có thể cấu hình:</p><ul><li>Báo cáo muốn gửi (công nợ, doanh thu, tồn kho, v.v.)</li><li>Tần suất gửi (hàng ngày, hàng tuần, hàng tháng)</li><li>Định dạng tệp đính kèm (XLSX, CSV, PDF)</li><li>Danh sách người nhận</li></ul><p>Tính năng này đặc biệt hữu ích cho việc cập nhật tình hình kinh doanh cho ban lãnh đạo một cách tự động và kịp thời.</p>',18)])])}const p=h(l,[["render",o]]);export{s as __pageData,p as default};
